record.field:
if line._name == 'sale.order.line':
    result = 0

decay = line.env['commission.decay'].search([('year', '=', line.move_id.year_project)], limit=1)
decay_val = 0
if decay:
    decay_val = decay.percentage / 100
if line._name == 'account.move.line':
    partial = (line.price_subtotal / 100) * 5 * decay_val
    result = partial / len(line.agent_ids)
